document.body.appendChild(app);

const $ = (id) => document.getElementById(id);
const statusEl = $("status");

function setStatus(message) {
  statusEl.textContent = message;
}

async function getProvider() {
  const rpcUrl = $("rpcUrl").value.trim();
  if (rpcUrl) return new ethers.JsonRpcProvider(rpcUrl);
  if (window.ethereum) return new ethers.BrowserProvider(window.ethereum);
  throw new Error("No RPC URL provided and no injected wallet found.");
}

async function getSigner(provider) {
  const privateKey = $("privateKey").value.trim();
  if (privateKey) {
    return new ethers.Wallet(privateKey, provider);
  }
  if (provider instanceof ethers.BrowserProvider) {
    return await provider.getSigner();
  }
  throw new Error("Provide a private key or connect an injected wallet.");
}

function parseAbi() {
  const raw = $("abiJson").value.trim();
  if (!raw) throw new Error("ABI JSON is required.");
  return JSON.parse(raw);
}

function parseArgs() {
  const raw = $("functionArgs").value.trim();
  if (!raw) return [];
  return JSON.parse(raw);
}

async function buildTx({ estimateOnly = false } = {}) {
  const provider = await getProvider();
  const signer = await getSigner(provider);
  const contractAddress = $("contractAddress").value.trim();
  const functionName = $("functionName").value.trim();
  const abi = parseAbi();
  const args = parseArgs();

  if (!ethers.isAddress(contractAddress)) throw new Error("Invalid contract address.");
  if (!functionName) throw new Error("Function name is required.");

  const contract = new ethers.Contract(contractAddress, abi, signer);
  const fragment = contract.interface.getFunction(functionName);
  const txRequest = await contract[fragment.name].populateTransaction(...args);

  const valueEth = $("valueEth").value.trim();
  if (valueEth) txRequest.value = ethers.parseEther(valueEth);

  const gasLimit = $("gasLimit").value.trim();
  if (gasLimit) txRequest.gasLimit = BigInt(gasLimit);

  txRequest.to = contractAddress;

  if (estimateOnly) {
    const estimated = await provider.estimateGas(txRequest);
    return { txRequest, estimated };
  }

  const populated = await signer.populateTransaction(txRequest);
  const sent = await signer.sendTransaction(populated);
  return { txRequest: populated, sent };
}

$("connectBtn").addEventListener("click", async () => {
  try {
    if (!window.ethereum) throw new Error("No injected wallet found.");
    const provider = new ethers.BrowserProvider(window.ethereum);
    await provider.send("eth_requestAccounts", []);
    const signer = await provider.getSigner();
    const address = await signer.getAddress();
    setStatus(`Connected wallet: ${address}`);
  } catch (err) {
    setStatus(`Error: ${err.message || err}`);
  }
});

$("estimateBtn").addEventListener("click", async () => {
  try {
    setStatus("Estimating gas...");
    const result = await buildTx({ estimateOnly: true });
    setStatus(
      JSON.stringify(
        {
          estimatedGas: result.estimated.toString(),
          txRequest: Object.fromEntries(
            Object.entries(result.txRequest).map(([k, v]) => [
              k,
              typeof v === "bigint" ? v.toString() : v,
            ])
          ),
        },
        null,
        2
      )
    );
  } catch (err) {
    setStatus(`Error: ${err.message || err}`);
  }
});

$("sendBtn").addEventListener("click", async () => {
  try {
    setStatus("Building and sending transaction...");
    const result = await buildTx();
    const tx = result.sent;
    setStatus(
      JSON.stringify(
        {
          hash: tx.hash,
          nonce: tx.nonce,
          to: tx.to,
          from: tx.from,
          value: tx.value ? tx.value.toString() : undefined,
          gasLimit: tx.gasLimit ? tx.gasLimit.toString() : undefined,
          txRequest: Object.fromEntries(
            Object.entries(result.txRequest).map(([k, v]) => [
              k,
              typeof v === "bigint" ? v.toString() : v,
            ])
          ),
        },
        null,
        2
      )
    );
  } catch (err) {
    setStatus(`Error: ${err.message || err}`);
  }
});